INSERT INTO wbs_project (
    project_id, project_name, location, contract_amount,
    status, description, start_date, end_date,
    client_name, manager_name
) VALUES (
    #{projectId}, #{projectName}, #{location}, #{contractAmount},
    #{status}, #{description},
    NULLIF(#{startDate}, '')::DATE, NULLIF(#{endDate}, '')::DATE,
    #{clientName}, #{managerName}
)

mapper.delete:
WITH bim_parents AS (
    SELECT task_id FROM wbs_task
    WHERE wbs_project_id = #{wbsProjectId}
      AND notes LIKE 'BIM:' || #{bimProjectId} || ':%'
)
DELETE FROM wbs_task
WHERE wbs_project_id = #{wbsProjectId}
  AND (
      notes LIKE 'BIM:' || #{bimProjectId} || ':%'
      OR parent_task_id IN (SELECT task_id FROM bim_parents)
  )
